13→sealed class Screen(val route: String) {
14→    object Home : Screen("home")
15→    object Detail : Screen("detail/{hotspotId}") {
16→        fun createRoute(hotspotId: String) = "detail/$hotspotId"
17→    }
18→    object Settings : Screen("settings")
19→}
20→
21→@Composable
22→fun AppNavigation(
23→    navController: NavHostController = rememberNavController()
24→) {
25→    NavHost(
26→        navController = navController,
27→        startDestination = Screen.Home.route
28→    ) {
29→        composable(Screen.Home.route) {
30→            HomeScreen(
31→                onItemClick = { hotspot ->
32→                    navController.navigate(Screen.Detail.createRoute(hotspot.id))
33→                },
34→                onSettingsClick = {
35→                    navController.navigate(Screen.Settings.route)
36→                }
37→            )
38→        }
39→
40→        composable(Screen.Detail.route) { backStackEntry ->
41→            val hotspotId = backStackEntry.arguments?.getString("hotspotId") ?: ""
42→            DetailScreen(
43→                hotspotId = hotspotId,
44→                onBackClick = {
45→                    navController.popBackStack()
46→                }
47→            )
48→        }
49→
50→        composable(Screen.Settings.route) {
51→            SettingsScreen(
52→                onBackClick = {
53→                    navController.popBackStack()
54→                }
55→            )
56→        }
57→    }
58→}
