 19→@HiltViewModel
 20→class HomeViewModel @Inject constructor(
 21→    private val getHotspotsUseCase: GetHotspotsUseCase,
 22→    private val refreshHotspotsUseCase: RefreshHotspotsUseCase,
 23→    private val hotspotActionsUseCase: HotspotActionsUseCase
 24→) : ViewModel() {
 25→
 26→    private val _state = MutableStateFlow(HomeState())
 27→    val state = _state.asStateFlow()
 28→
 29→    init {
 30→        loadHotspots()
 31→    }
 32→
 33→    private fun loadHotspots() {
 34→        viewModelScope.launch {
 35→            _state.update { it.copy(isLoading = true) }
 36→
 37→            getHotspotsUseCase(_state.value.filterState)
 38→                .catch { e ->
 39→                    _state.update {
 40→                        it.copy(
 41→                            error = e.message,
 42→                            isLoading = false
 43→                        )
 44→                    }
 45→                }
 46→                .collect { hotspots ->
 47→                    _state.update {
 48→                        it.copy(
 49→                            hotspots = hotspots,
 50→                            isLoading = false,
 51→                            error = null
 52→                        )
 53→                    }
 54→                }
 55→        }
 56→    }
 57→
 58→    fun refresh() {
 59→        viewModelScope.launch {
 60→            _state.update { it.copy(isRefreshing = true) }
 61→
 62→            refreshHotspotsUseCase()
 63→                .onSuccess {
 64→                    _state.update { it.copy(isRefreshing = false, error = null) }
 65→                }
 66→                .onFailure { e ->
 67→                    _state.update {
 68→                        it.copy(
 69→                            isRefreshing = false,
 70→                            error = e.message
 71→                        )
 72→                    }
 73→                }
 74→        }
 75→    }
 76→
 77→    fun toggleBookmark(hotspotId: String, isCurrentlyBookmarked: Boolean) {
 78→        viewModelScope.launch {
 79→            hotspotActionsUseCase.toggleBookmark(hotspotId, isCurrentlyBookmarked)
 80→        }
 81→    }
 82→
 83→    fun markAsRead(hotspotId: String) {
 84→        viewModelScope.launch {
 85→            hotspotActionsUseCase.markAsRead(hotspotId)
 86→        }
 87→    }
 88→
 89→    fun updateFilter(filterState: FilterState) {
 90→        _state.update { it.copy(filterState = filterState) }
 91→        loadHotspots()
 92→    }
 93→
 94→    fun toggleFilterSheet() {
 95→        _state.update { it.copy(showFilterSheet = !it.showFilterSheet) }
 96→    }
 97→
 98→    fun toggleSearchBar() {
 99→        _state.update {
100→            it.copy(
101→                showSearchBar = !it.showSearchBar,
102→                searchQuery = if (it.showSearchBar) "" else it.searchQuery
103→            )
104→        }
105→    }
106→
107→    fun updateSearchQuery(query: String) {
108→        _state.update {
109→            it.copy(
110→                searchQuery = query,
111→                filterState = it.filterState.copy(searchQuery = query)
112→            )
113→        }
114→        loadHotspots()
115→    }
116→
117→    fun clearError() {
118→        _state.update { it.copy(error = null) }
119→    }
120→}
